import subprocess
import os

def generate_requirements_txt():
    # Run pip freeze with hashes to generate requirements.txt
    subprocess.run(['pip', 'freeze', '--all', '--hash=sha256'], stdout=open('requirements.txt', 'w'))

def update_requirements_txt():
    # Update the existing requirements.txt file with latest versions and hashes
    os.system('pip-compile --upgrade')

def create_poetry_lock():
    # Initialize poetry if not already initialized
    subprocess.run(['poetry', 'init'], check=True)
    # Generate lock file
    subprocess.run(['poetry', 'lock'])

def update_poetry_lock():
    # Update the lock file with latest versions
    subprocess.run(['poetry', 'update'])

# Example usage:
if __name__ == "__main__":
    choice = input("Choose an option:\n1. Generate requirements.txt\n2. Update requirements.txt\n3. Create poetry.lock\n4. Update poetry.lock\n")
    
    if choice == '1':
        generate_requirements_txt()
    elif choice == '2':
        update_requirements_txt()
    elif choice == '3':
        create_poetry_lock()
    elif choice == '4':
        update_poetry_lock()
    else:
        print("Invalid option selected.")